- Imports: `ImageModelV3`, `SharedV3Warning` from `@ai-sdk/provider`; `FetchFunction`, `combineHeaders`, `createJsonResponseHandler`, `createJsonErrorResponseHandler`, `postJsonToApi`, `parseProviderOptions`, `lazySchema`, `zodSchema`, `InferSchema` from `@ai-sdk/provider-utils`; `z` from `zod/v4`
- Config interface: `PixelArtImageModelConfig` with `provider`, `baseURL`, `headers: () => Record<string,string>`, `fetch?: FetchFunction`
- Class: `PixelArtImageModel implements ImageModelV3`
  - `specificationVersion = 'v3'` (readonly)
  - `maxImagesPerCall = 4` (readonly)
  - `provider` getter from config
  - `modelId` as constructor parameter
- `doGenerate()` logic:
  1. Collect warnings for unsupported features: `aspectRatio`, `seed`, `files`, `mask`
  2. Parse provider-specific options via `parseProviderOptions` using `pixelArtImageOptionsSchema` (validates `style` and `pixelDensity`)
  3. Call `postJsonToApi` to `POST {baseURL}/images/generate` with body: `{ prompt, model: modelId, n, size, style, pixel_density }`
  4. Use `createJsonResponseHandler(pixelArtResponseSchema)` for success, `createJsonErrorResponseHandler` for errors
  5. Map response `data[].b64_json` → `images` array (base64 strings)
  6. Return `{ images, warnings, response: { timestamp, modelId, headers } }`

**Schemas (using `lazySchema` + `zodSchema`):**
- `pixelArtResponseSchema`: `z.object({ data: z.array(z.object({ b64_json: z.string() })) })`
- `pixelArtErrorSchema`: `z.object({ error: z.object({ message: z.string(), code: z.string().nullish() }) })`
- `pixelArtImageOptionsSchema`: `z.object({ style: z.enum(['pixel','retro','8bit']).nullish(), pixelDensity: z.number().nullish() }).passthrough()`

---

### 8. `packages/pixelart/src/pixelart-provider.ts`

The factory function and provider interface.

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

export const pixelart = createPixelArt();
```

