## 7. Provider Factory Function Pattern

Location: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775334274173-ulgua0/packages/luma/src/luma-provider.ts`

```typescript
export interface LumaProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface LumaProvider extends ProviderV3 {
  image(modelId: LumaImageModelId): ImageModelV3;
  imageModel(modelId: LumaImageModelId): ImageModelV3;
  textEmbeddingModel(modelId: string): never;
}

const defaultBaseURL = 'https://api.lumalabs.ai';

export function createLuma(options: LumaProviderSettings = {}): LumaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'LUMA_API_KEY',
          description: 'Luma',
        })}`,
        ...options.headers,
      },
      `ai-sdk/luma/${VERSION}`,
    );

  const createImageModel = (modelId: LumaImageModelId) =>
    new LumaImageModel(modelId, {
      provider: 'luma.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
    textEmbeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
  };
}

export const luma = createLuma();
```

**Pattern:**
- Settings interface with optional baseURL, headers, fetch, apiKey
- Provider interface extends ProviderV3 with specificationVersion: 'v3'
- Factory function creates model instances with config containing provider name, baseURL, headers function, fetch
- Unsupported model types throw NoSuchModelError
- Singleton instance exported as default

