import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  jsonSchema,
  parseProviderOptions,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

/**
 * Provider-specific options for PixelArt image generation.
 * Pass these via `providerOptions.pixelart` in `generateImage` calls.
 */
export interface PixelArtImageModelOptions {
  /**
   * The artistic style to apply to the generated image.
   *
   * - `pixel`: Classic pixel art style
   * - `retro`: Retro-inspired pixel art with a vintage feel
   * - `8bit`: 8-bit video game aesthetic
   */
  style?: 'pixel' | 'retro' | '8bit' | null;

  /**
   * The pixel density of the generated image.
   * Higher values produce finer detail. Defaults to 1.
   */
  pixelDensity?: number | null;
}

interface PixelArtGenerationResponse {
  data: Array<{ b64_json: string }>;
}

interface PixelArtErrorResponse {
  error: {
    message: string;
    type?: string | null;
    code?: string | null;
  };
}

export type PixelArtErrorData = PixelArtErrorResponse;

// Response schema — intentionally minimal to avoid breakage on API changes
const pixelArtGenerationResponseSchema =
  jsonSchema<PixelArtGenerationResponse>({
    type: 'object',
    properties: {
      data: {
        type: 'array',
        items: {
          type: 'object',
          properties: {
            b64_json: { type: 'string' },
          },
          required: ['b64_json'],
        },
      },
    },
    required: ['data'],
  });

const pixelArtErrorSchema = jsonSchema<PixelArtErrorResponse>({
  type: 'object',
  properties: {
    error: {
      type: 'object',
      properties: {
        message: { type: 'string' },
        type: { type: 'string' },
        code: { type: 'string' },
      },
      required: ['message'],
    },
  },
  required: ['error'],
});

/**
 * Provider options schema for PixelArt image generation.
 */
const pixelArtImageModelOptionsSchema = jsonSchema<PixelArtImageModelOptions>(
  {
    type: 'object',
    properties: {
      style: {
        type: 'string',
        enum: ['pixel', 'retro', '8bit'],
      },
      pixelDensity: {
        type: 'number',
        exclusiveMinimum: 0,
      },
    },
    additionalProperties: true,
  },
  {
    validate: (value: unknown) => {
      const opts = value as Record<string, unknown>;
      const validStyles = ['pixel', 'retro', '8bit'];

      if (opts?.style != null && !validStyles.includes(opts.style as string)) {
        return {
          success: false,
          error: new Error(
            `Invalid style "${opts.style}". Must be one of: ${validStyles.join(', ')}.`,
          ),
        };
      }

      if (
        opts?.pixelDensity != null &&
        (typeof opts.pixelDensity !== 'number' || opts.pixelDensity <= 0)
      ) {
        return {
          success: false,
          error: new Error('pixelDensity must be a positive number.'),
        };
      }

      return { success: true, value: opts as PixelArtImageModelOptions };
    },
  },
);

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support the `seed` option.',
      });
    }

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support input files for image generation.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support mask-based image editing.',
      });
    }

    // Parse and validate provider-specific options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const fullHeaders = combineHeaders(this.config.headers(), headers);

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: fullHeaders,
      body: {
        model: this.modelId,
        prompt,
        n: n ?? 1,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.style != null
          ? { style: pixelartOptions.style }
          : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (error: PixelArtErrorResponse) => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtGenerationResponseSchema,
      ),
    });

    const images = response.data.map(item =>
      convertBase64ToUint8Array(item.b64_json),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

